#!/usr/bin/env bash
export PATH=$PATH:/opt/homebrew/bin
export PATH="$PATH:/usr/local/bin"

source ~/.shell/credentials.sh

GITLAB_LOGO=""
FONT=( 'size=14' 'font=UbuntuMono' )
support_tickets=$(curl --silent --output -H "Content-Type: application/json" "https://gitlab.com/api/v4/projects/50754775/issues_statistics" --header "PRIVATE-TOKEN: $GITLAB_ACCESS_TOKEN" | jq '.')

echo "| $FONT image=$GITLAB_LOGO"
echo "---"
echo "Moovv Support Desk: $(echo $support_tickets | jq -er .statistics.counts.opened 2> /dev/null) | href=https://gitlab.com/moovv/support/-/issues/service_desk"
echo "---"
echo "Refresh | refresh=true"
